VALUES
  ('social-worker-moex-05670', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '《管子‧牧民》：「政之所興，在順民心；政之所廢，在逆民心。民惡憂勞，我佚樂之；民惡貧 賤，我富貴之；民惡危墜，我存安之；民惡滅絕，我生育之。」此段文字，提示為政者應有何種 胸襟？', '["民之所欲，常在我心", "得民者昌，失民者亡", "重義輕利，富民而教", "公忠體國，勤政愛民"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05671', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '銘金人云：「無多言，多言多敗；無多事，多事多患。」至哉斯戒也！能走者奪其翼，善飛者減 其指，有角者無上齒，豐後者無前足，蓋天道不使物有兼焉也。（《顏氏家訓‧省事》）此段文 字之旨意與下列何者相近？', '["人盡其才，地盡其利，物盡其用，貨暢其流", "巧者多勞，知者多憂，無能無求，飽食敖遊", "多為少善，不如執一；鼫鼠五能，不成伎術", "虛而不屈，動而愈出。多言數窮，不如守中"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05672', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '（齊景）公曰：「和與同異乎？」（晏子）對曰：「異。和如羹焉，水、火、醯、醢、鹽、梅， 以烹魚肉，燀之以薪，宰夫和之，齊之以味，濟其不及，以洩其過。君子食之，以平其心。君臣 亦然。君所謂可而有否焉，臣獻其否以成其可；君所謂否而有可焉；臣獻其可以去其否。」（《左 傳》昭公二十年） 依本段文意，晏子認為君臣之間應當採取何種態度？', '["和而且同", "和而不同", "同而不和", "不和不同"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05673', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '丘遲〈與陳伯之書〉：「所以廉公之思趙將，吳子之泣西河，人之情也，將軍獨無情哉？」其中 「廉公之思趙將，吳子之泣西河」隱含的情意，與下列選項最為相近的是：', '["總為浮雲能蔽日，長安不見使人愁", "但使龍城飛將在，不教胡馬渡陰山", "但願人長久，千里共嬋娟", "胡馬依北風，越鳥巢南枝"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05674', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '蘇軾〈赤壁賦〉：「且夫天地之間，物各有主。苟非吾之所有，雖一毫而莫取；惟江上之清風， 與山間之明月，耳得之而為聲，目遇之而成色。取之無禁，用之不竭。是造物者之無盡藏也，而 吾與子之所共適。」下列選項，何者最貼近本段文字之意旨？', '["江山風月本無主，惟閒者能得之", "江山風月可取之無禁，用之不竭", "江山風月當前，宜適時順物怡情", "人生變化無常，應學會及時行樂"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05675', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '荊軻感燕丹之義，函匕首入秦，劫秦皇，將以存燕、霸諸侯。事雖不成，然亦壯士也，惜其智謀 不足以知變識機。始皇之道異於齊桓，曹沫功成，荊軻殺身，其所遭者然也。及欲促檻車、駕秦 王以如燕，童子婦人且明其不能，而軻行之，其弗就也非不幸。燕丹之心，苟可以報秦，雖舉燕 國而不顧，況美人哉？軻不曉而當之，陋矣。（李翱〈題燕太子丹傳後〉） 根據上文，下列選項敘述何者正確？', '["作者指出燕太子丹為天下正義而欲刺殺秦王", "作者批判荊軻不知效法曹沫功成身退，以致事敗身亡", "作者稱賞燕太子丹與荊軻君臣相得、圖舉大事的豪情壯志", "作者認為燕太子丹與荊軻的失敗，是未看清當時情勢的必然結果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05676', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '承上題，下列「」中的字，那一組前後意義相同？', '["其弗「就」也非不幸／待到重陽日，還來「就」菊花", "駕秦王以「如」燕／縱一葦之所「如」，凌萬頃之茫然", "事雖不成，「然」亦壯士也／荊軻殺身，其所遭者「然」也", "荊軻感燕丹「之」義／童子婦人且明其不能，而軻行「之」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "723ef211c942", "answer_pdf_sha1": "5f3cec94b692", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05677', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '①下里巴人  ②下氣怡聲  ③高山仰止  ④高山流水  ⑤金風玉露  ⑥金聲玉振。上列可以用來形容音 樂的成語有：', '["", "", "⑥", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05678', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列題辭使用場合錯誤的是：', '["「君子攸居」祝賀新居落成", "「石麟呈彩」祝賀生子之喜", "「達材成德」祝賀學校校慶", "「碩德堪欽」祝賀長者大壽"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05679', 'social-worker', 'social-worker-moex-105-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '古人名字常有一些相應的關聯性，有些意義相成，有些則取相反意義。下列選項中三者的命名命字方式 一致的是：', '["班固，字孟堅／韓愈，字退之／端木賜，字子貢", "杜甫，字子美／朱熹，字元晦／趙孟頫，字子昂", "冉耕，字伯牛／管同，字異之／王念孫，字懷祖", "孟軻，字子輿／蘇軾，字子瞻／陶淵明，字元亮"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "bd0dfa1afbb5", "answer_pdf_sha1": "a508365c925c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
